-- Finance Phase 7.5: savings, interest, fixed deposits and personal banking foundations.
ALTER TYPE public.financial_transaction_category ADD VALUE IF NOT EXISTS 'fixed_deposit_early_withdrawal';
ALTER TYPE public.financial_transaction_category ADD VALUE IF NOT EXISTS 'fixed_deposit_maturity';
ALTER TYPE public.financial_transaction_category ADD VALUE IF NOT EXISTS 'bank_transfer';
ALTER TYPE public.financial_transaction_category ADD VALUE IF NOT EXISTS 'bank_fee';

DO $$ BEGIN CREATE TYPE public.savings_product_kind AS ENUM ('current','easy_access_savings','premium_savings','fixed_term_deposit','business_savings','band_reserve'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;
DO $$ BEGIN CREATE TYPE public.fixed_deposit_status AS ENUM ('active','matured','withdrawn','renewed','cancelled'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;
DO $$ BEGIN CREATE TYPE public.banking_transfer_frequency AS ENUM ('weekly','monthly','threshold','percentage_of_income'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

CREATE TABLE IF NOT EXISTS public.savings_products (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(), provider_id uuid NOT NULL REFERENCES public.banking_providers(id), product_code text NOT NULL UNIQUE, product_name text NOT NULL,
  product_kind public.savings_product_kind NOT NULL, eligible_owner_types public.financial_owner_type[] NOT NULL, supported_currencies char(3)[] NOT NULL,
  annual_rate_basis_points integer NOT NULL DEFAULT 0, minimum_balance_minor bigint NOT NULL DEFAULT 0, maximum_balance_minor bigint,
  withdrawals_allowed boolean NOT NULL DEFAULT true, withdrawal_rules jsonb NOT NULL DEFAULT '{}', early_withdrawal_penalty_basis_points integer NOT NULL DEFAULT 0,
  opening_fee_minor bigint NOT NULL DEFAULT 0, promotional_rates jsonb NOT NULL DEFAULT '[]', future_rate_changes jsonb NOT NULL DEFAULT '[]', status text NOT NULL DEFAULT 'active', created_at timestamptz NOT NULL DEFAULT timezone('utc',now()), updated_at timestamptz NOT NULL DEFAULT timezone('utc',now()), metadata jsonb NOT NULL DEFAULT '{}'
);
CREATE INDEX IF NOT EXISTS savings_products_provider_idx ON public.savings_products(provider_id, product_kind, status);

CREATE TABLE IF NOT EXISTS public.fixed_deposits (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(), bank_account_id uuid NOT NULL REFERENCES public.bank_accounts(id), product_id uuid REFERENCES public.savings_products(id), owner_type public.financial_owner_type NOT NULL, owner_id uuid NOT NULL,
  provider_id uuid NOT NULL REFERENCES public.banking_providers(id), amount_minor bigint NOT NULL CHECK(amount_minor>0), currency_code char(3) NOT NULL, opening_date date NOT NULL DEFAULT CURRENT_DATE, maturity_date date NOT NULL,
  agreed_rate_basis_points integer NOT NULL, accrued_interest_minor bigint NOT NULL DEFAULT 0, penalty_rules jsonb NOT NULL DEFAULT '{}', auto_renew boolean NOT NULL DEFAULT false, renewal_product_id uuid REFERENCES public.savings_products(id), payout_bank_account_id uuid REFERENCES public.bank_accounts(id), status public.fixed_deposit_status NOT NULL DEFAULT 'active', opened_transaction_id uuid REFERENCES public.financial_transactions(id), closed_transaction_id uuid REFERENCES public.financial_transactions(id), created_at timestamptz NOT NULL DEFAULT timezone('utc',now()), metadata jsonb NOT NULL DEFAULT '{}', CONSTRAINT fixed_deposit_maturity_after_open CHECK(maturity_date>opening_date)
);
CREATE INDEX IF NOT EXISTS fixed_deposits_owner_idx ON public.fixed_deposits(owner_type,owner_id,status,maturity_date);

CREATE TABLE IF NOT EXISTS public.deposit_protection_schemes (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), scheme_code text NOT NULL UNIQUE, name text NOT NULL, country text NOT NULL, currency_code char(3) NOT NULL, protection_limit_minor bigint NOT NULL CHECK(protection_limit_minor>0), status text NOT NULL DEFAULT 'active', metadata jsonb NOT NULL DEFAULT '{}');
CREATE TABLE IF NOT EXISTS public.deposit_protected_institutions (scheme_id uuid REFERENCES public.deposit_protection_schemes(id), provider_id uuid REFERENCES public.banking_providers(id), effective_from date NOT NULL DEFAULT CURRENT_DATE, effective_to date, PRIMARY KEY(scheme_id,provider_id,effective_from));
CREATE TABLE IF NOT EXISTS public.savings_goals (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), owner_type public.financial_owner_type NOT NULL, owner_id uuid NOT NULL, name text NOT NULL, target_minor bigint NOT NULL CHECK(target_minor>0), current_minor bigint NOT NULL DEFAULT 0, currency_code char(3) NOT NULL, target_date date, funding_bank_account_id uuid REFERENCES public.bank_accounts(id), destination_bank_account_id uuid REFERENCES public.bank_accounts(id), auto_transfer_enabled boolean NOT NULL DEFAULT false, status text NOT NULL DEFAULT 'active', created_at timestamptz NOT NULL DEFAULT timezone('utc',now()), metadata jsonb NOT NULL DEFAULT '{}');
CREATE TABLE IF NOT EXISTS public.banking_scheduled_transfers (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), owner_type public.financial_owner_type NOT NULL, owner_id uuid NOT NULL, source_bank_account_id uuid NOT NULL REFERENCES public.bank_accounts(id), destination_bank_account_id uuid NOT NULL REFERENCES public.bank_accounts(id), amount_minor bigint, percentage_basis_points integer, threshold_minor bigint, currency_code char(3) NOT NULL, frequency public.banking_transfer_frequency NOT NULL, next_run_date date, status text NOT NULL DEFAULT 'active', created_at timestamptz NOT NULL DEFAULT timezone('utc',now()), metadata jsonb NOT NULL DEFAULT '{}');
CREATE TABLE IF NOT EXISTS public.banking_notifications (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), owner_type public.financial_owner_type NOT NULL, owner_id uuid NOT NULL, provider_id uuid REFERENCES public.banking_providers(id), notification_type text NOT NULL, title text NOT NULL, body text NOT NULL, severity text NOT NULL DEFAULT 'info', related_entity_type text, related_entity_id uuid, read_at timestamptz, created_at timestamptz NOT NULL DEFAULT timezone('utc',now()), metadata jsonb NOT NULL DEFAULT '{}');

CREATE OR REPLACE VIEW public.banking_provider_liquidity AS
SELECT bp.id provider_id, bp.brand_name provider_name, ba.currency_code, COALESCE(sum(fa.current_balance_minor),0) customer_deposits_minor, COALESCE((SELECT sum(amount_minor) FROM public.fixed_deposits fd WHERE fd.provider_id=bp.id AND fd.currency_code=ba.currency_code AND fd.status='active'),0) locked_deposits_minor, COALESCE((SELECT sum(outstanding_principal_minor) FROM public.loan_contracts lc WHERE lc.provider_id=bp.id AND lc.currency_code=ba.currency_code AND lc.status IN ('active','grace_period','delinquent')),0) outstanding_loans_minor, 2000 reserve_requirement_bps, GREATEST(0,COALESCE(sum(fa.current_balance_minor),0)-COALESCE((SELECT sum(outstanding_principal_minor) FROM public.loan_contracts lc WHERE lc.provider_id=bp.id AND lc.currency_code=ba.currency_code AND lc.status IN ('active','grace_period','delinquent')),0)) available_reserves_minor
FROM public.banking_providers bp JOIN public.bank_accounts ba ON ba.provider_id=bp.id JOIN public.financial_accounts fa ON fa.id=ba.linked_finance_account_id GROUP BY bp.id,bp.brand_name,ba.currency_code;

CREATE OR REPLACE VIEW public.banking_deposit_protection_summary AS
SELECT ba.owner_type,ba.owner_id,ba.provider_id,ba.currency_code,fa.current_balance_minor balance_minor,dps.protection_limit_minor,LEAST(fa.current_balance_minor,COALESCE(dps.protection_limit_minor,0)) protected_minor,GREATEST(0,fa.current_balance_minor-COALESCE(dps.protection_limit_minor,0)) unprotected_minor
FROM public.bank_accounts ba JOIN public.financial_accounts fa ON fa.id=ba.linked_finance_account_id LEFT JOIN public.deposit_protected_institutions dpi ON dpi.provider_id=ba.provider_id AND (dpi.effective_to IS NULL OR dpi.effective_to>=CURRENT_DATE) LEFT JOIN public.deposit_protection_schemes dps ON dps.id=dpi.scheme_id AND dps.currency_code=ba.currency_code AND dps.status='active';

CREATE OR REPLACE FUNCTION public.calculate_deposit_daily_interest(p_balance_minor bigint,p_rate_bps integer) RETURNS bigint LANGUAGE sql IMMUTABLE AS $$ SELECT GREATEST(0,floor(GREATEST(0,p_balance_minor)::numeric * GREATEST(0,p_rate_bps)::numeric / 10000 / 365)::bigint) $$;

CREATE OR REPLACE FUNCTION public.get_banking_dashboard() RETURNS jsonb LANGUAGE plpgsql SECURITY DEFINER SET search_path=public AS $$
DECLARE pid uuid; result jsonb; BEGIN SELECT id INTO pid FROM public.profiles WHERE user_id=auth.uid() LIMIT 1; IF pid IS NULL THEN RETURN jsonb_build_object('accounts','[]'::jsonb,'loans','[]'::jsonb,'recentActivity','[]'::jsonb,'notifications','[]'::jsonb); END IF;
SELECT jsonb_build_object('accounts',COALESCE((SELECT jsonb_agg(jsonb_build_object('id',ba.id,'accountType',ba.account_type,'currencyCode',ba.currency_code,'balanceMinor',fa.current_balance_minor,'providerName',bp.brand_name,'restrictionSummary',CASE WHEN ba.status='restricted' THEN 'Restricted' ELSE 'Unrestricted' END,'annualRateBps',COALESCE((ba.interest_configuration->>'annual_rate_bps')::int,bp.base_deposit_rate_basis_points))) FROM public.bank_accounts ba JOIN public.financial_accounts fa ON fa.id=ba.linked_finance_account_id JOIN public.banking_providers bp ON bp.id=ba.provider_id WHERE ba.owner_type='player' AND ba.owner_id=pid),'[]'::jsonb),'loans','[]'::jsonb,'creditProfile',COALESCE((SELECT jsonb_build_object('band',credit_band,'score',credit_score,'positiveFactors',jsonb_build_array('Savings balances and on-time payments improve your banking relationship.'),'negativeFactors','[]'::jsonb) FROM public.banking_customer_profiles WHERE owner_type='player' AND owner_id=pid),jsonb_build_object('band','Building','positiveFactors',jsonb_build_array('Open a current or savings account to start banking.'),'negativeFactors','[]'::jsonb)),'recentActivity','[]'::jsonb,'savingsSummary',jsonb_build_object('netWorthMinor',COALESCE((SELECT sum(fa.current_balance_minor) FROM public.bank_accounts ba JOIN public.financial_accounts fa ON fa.id=ba.linked_finance_account_id WHERE ba.owner_type='player' AND ba.owner_id=pid),0),'cashMinor',COALESCE((SELECT sum(fa.current_balance_minor) FROM public.bank_accounts ba JOIN public.financial_accounts fa ON fa.id=ba.linked_finance_account_id WHERE ba.owner_type='player' AND ba.owner_id=pid AND ba.account_type='current'),0),'savingsMinor',COALESCE((SELECT sum(fa.current_balance_minor) FROM public.bank_accounts ba JOIN public.financial_accounts fa ON fa.id=ba.linked_finance_account_id WHERE ba.owner_type='player' AND ba.owner_id=pid AND ba.account_type<>'current'),0),'lockedDepositsMinor',COALESCE((SELECT sum(amount_minor) FROM public.fixed_deposits WHERE owner_type='player' AND owner_id=pid AND status='active'),0),'monthlyInterestMinor',COALESCE((SELECT sum(accrued_amount_minor-paid_amount_minor) FROM public.deposit_interest_accruals dia JOIN public.bank_accounts ba ON ba.id=dia.bank_account_id WHERE ba.owner_type='player' AND ba.owner_id=pid),0),'interestEarnedYtdMinor',COALESCE((SELECT sum(paid_amount_minor) FROM public.deposit_interest_accruals dia JOIN public.bank_accounts ba ON ba.id=dia.bank_account_id WHERE ba.owner_type='player' AND ba.owner_id=pid AND dia.created_at>=date_trunc('year',now())),0),'currencyCode','USD','nextMaturityDate',(SELECT min(maturity_date)::text FROM public.fixed_deposits WHERE owner_type='player' AND owner_id=pid AND status='active')),'cashFlowAnalytics',jsonb_build_object('incomeMinor',0,'expensesMinor',0,'savingsRateBps',0,'financialHealth','building','largestExpenseCategories','[]'::jsonb),'savingsGoals',COALESCE((SELECT jsonb_agg(jsonb_build_object('id',id,'name',name,'targetMinor',target_minor,'currentMinor',current_minor,'currencyCode',currency_code,'completionBps',LEAST(10000,floor(current_minor::numeric*10000/target_minor)::int),'projectedCompletionDate',target_date)) FROM public.savings_goals WHERE owner_type='player' AND owner_id=pid AND status='active'),'[]'::jsonb),'notifications',COALESCE((SELECT jsonb_agg(jsonb_build_object('id',id,'type',notification_type,'title',title,'body',body,'severity',severity,'createdAt',created_at) ORDER BY created_at DESC) FROM public.banking_notifications WHERE owner_type='player' AND owner_id=pid AND read_at IS NULL LIMIT 5),'[]'::jsonb)) INTO result; RETURN result; END $$;

GRANT SELECT ON public.savings_products, public.banking_provider_liquidity, public.banking_deposit_protection_summary TO authenticated;
GRANT EXECUTE ON FUNCTION public.calculate_deposit_daily_interest(bigint,integer) TO authenticated;
